import React from 'react';
import { useForm } from '@formspree/react';
import "../Feedback/Feedback.css";

const Feedback = () => {
  const [state, handleSubmit] = useForm("xeewypab");

  if (state.succeeded) {
    return (
      <div className="feedback-container success-message">
        <h2>Thank you Trainer!</h2>
        <p>Your feedback has been received and will help improve our journey.</p>
        <button onClick={() => window.location.reload()}>Send another</button>
      </div>
    );
  }

  return (
    <div className="feedback-container">
      <h1>Trainer Feedback</h1>
      <form onSubmit={handleSubmit} className="feedback-form">
        <label>Name</label>
        <input type="text" name="name" required placeholder="Enter your name" />

        <label>How are you enjoying the Pokédex Website</label>
        <textarea name="message" rows="5" required placeholder="Share your thoughts" />

        <button type="submit" disabled={state.submitting}>
          {state.submitting ? "Submitting..." : "Submit Feedback"}
        </button>
      </form>
    </div>
  );
};

export default Feedback;
